"""Leave-one-subject-out evaluation."""

from __future__ import annotations

import json
from pathlib import Path

import numpy as np
import pandas as pd
from sklearn.metrics import (
    balanced_accuracy_score,
    confusion_matrix,
    f1_score,
    roc_auc_score,
)
from sklearn.model_selection import LeaveOneGroupOut
from sklearn.preprocessing import LabelEncoder

from wesad_arousal.modeling.baselines import get_model, list_models


META_COLUMNS = {
    "subject_id",
    "window_start_s",
    "window_end_s",
    "label_code",
    "label_name",
    "binary_label",
    "label_purity",
}


def _prepare_xy(df: pd.DataFrame, task: str) -> tuple[np.ndarray, np.ndarray, np.ndarray, list[str]]:
    if task == "binary":
        mask = df["binary_label"].notna()
        work = df.loc[mask].copy()
        y = work["binary_label"].astype(int).to_numpy()
    else:
        work = df.copy()
        y = LabelEncoder().fit_transform(work["label_name"].astype(str))

    feature_cols = [col for col in work.columns if col not in META_COLUMNS]
    X = work[feature_cols].replace([np.inf, -np.inf], np.nan).fillna(0.0).to_numpy(dtype=float)
    groups = work["subject_id"].astype(str).to_numpy()
    return X, y, groups, feature_cols


def _roc_auc_safe(y_true: np.ndarray, y_score: np.ndarray, task: str) -> float | None:
    if task != "binary":
        return None
    if len(np.unique(y_true)) < 2:
        return None
    try:
        return float(roc_auc_score(y_true, y_score))
    except ValueError:
        return None


def run_loso_evaluation(
    features_df: pd.DataFrame,
    cfg: dict,
    task: str | None = None,
    model_names: list[str] | None = None,
) -> dict:
    task = task or cfg.get("modeling", {}).get("task", "binary")
    model_names = model_names or list_models(cfg)
    X, y, groups, feature_cols = _prepare_xy(features_df, task)

    logo = LeaveOneGroupOut()
    results = {"task": task, "feature_columns": feature_cols, "models": {}}

    for model_name in model_names:
        fold_metrics = []
        y_true_all = []
        y_pred_all = []
        y_score_all = []

        for train_idx, test_idx in logo.split(X, y, groups):
            model = get_model(model_name, random_state=cfg.get("modeling", {}).get("random_state", 42))
            model.fit(X[train_idx], y[train_idx])
            preds = model.predict(X[test_idx])
            y_true_all.extend(y[test_idx])
            y_pred_all.extend(preds)

            if task == "binary" and hasattr(model, "predict_proba"):
                scores = model.predict_proba(X[test_idx])[:, 1]
                y_score_all.extend(scores)

            fold_metrics.append(
                {
                    "held_out_subject": groups[test_idx][0],
                    "balanced_accuracy": balanced_accuracy_score(y[test_idx], preds),
                    "macro_f1": f1_score(y[test_idx], preds, average="macro"),
                }
            )

        summary = {
            "balanced_accuracy_mean": float(np.mean([m["balanced_accuracy"] for m in fold_metrics])),
            "balanced_accuracy_std": float(np.std([m["balanced_accuracy"] for m in fold_metrics])),
            "macro_f1_mean": float(np.mean([m["macro_f1"] for m in fold_metrics])),
            "macro_f1_std": float(np.std([m["macro_f1"] for m in fold_metrics])),
            "per_subject": fold_metrics,
            "confusion_matrix": confusion_matrix(y_true_all, y_pred_all).tolist(),
        }

        if task == "binary" and y_score_all:
            auc = _roc_auc_safe(np.asarray(y_true_all), np.asarray(y_score_all), task)
            summary["roc_auc"] = auc

        results["models"][model_name] = summary

    return results


def save_evaluation_outputs(results: dict, cfg: dict, tag: str = "default") -> Path:
    outputs_dir = Path(cfg["paths"]["outputs_dir"])
    outputs_dir.mkdir(parents=True, exist_ok=True)

    metrics_path = outputs_dir / f"metrics_{tag}.json"
    with metrics_path.open("w", encoding="utf-8") as handle:
        json.dump(results, handle, indent=2)

    rows = []
    for model_name, payload in results["models"].items():
        rows.append(
            {
                "model": model_name,
                "task": results["task"],
                "cv": "LOSO",
                "balanced_accuracy": payload["balanced_accuracy_mean"],
                "macro_f1": payload["macro_f1_mean"],
                "roc_auc": payload.get("roc_auc"),
            }
        )
    summary_df = pd.DataFrame(rows)
    summary_df.to_csv(outputs_dir / f"metrics_summary_{tag}.csv", index=False)
    return metrics_path


def filter_feature_groups(features_df: pd.DataFrame, prefixes: list[str]) -> pd.DataFrame:
    keep_cols = [col for col in features_df.columns if col in META_COLUMNS]
    for prefix in prefixes:
        keep_cols.extend([col for col in features_df.columns if col.startswith(prefix)])
    return features_df[sorted(set(keep_cols))]
